parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    let rec;
    try {
      const text = item.json.content[0].text;
      rec = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      rec = match ? JSON.parse(match[0]) : {recommended_monthly_spend:0, reasoning:'Analysis unavailable'};
    }
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      current_spend: rec.current_monthly_spend || 0,
      recommended_spend: rec.recommended_monthly_spend || 0,
      budget_by_channel: rec.budget_by_channel || {},
      reasoning: rec.reasoning || '',
      expected_roas: rec.expected_roas || 0,
      expected_reach: rec.expected_reach || 0,
      key_optimizations: rec.key_optimizations || [],
      confidence_level: rec.confidence_level || 'medium'
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
